<?php declare(strict_types=1); ?>
<div class="wrap edis-admin" data-edis-page="diagnostics"><h1><?php echo esc_html__('Diagnostics','edis-evidence-exporter'); ?></h1><p class="edis-lead"><?php echo esc_html__('This report is privacy-safe. The worker test executes a minimal real source export rather than checking function names only.','edis-evidence-exporter'); ?></p>
<div class="edis-actions"><button type="button" class="button button-primary" data-edis-action="worker-test"><?php echo esc_html__('Run safe worker test','edis-evidence-exporter'); ?></button><button type="button" class="button" data-edis-action="copy-diagnostics"><?php echo esc_html__('Copy report','edis-evidence-exporter'); ?></button></div><div id="edis-worker-test-result" aria-live="polite"></div>
<div class="edis-table-wrap"><table class="widefat striped"><thead><tr><th><?php echo esc_html__('Check','edis-evidence-exporter'); ?></th><th><?php echo esc_html__('State','edis-evidence-exporter'); ?></th><th><?php echo esc_html__('Detail','edis-evidence-exporter'); ?></th></tr></thead><tbody><?php foreach($report['checks'] as $check): ?><tr><td><?php echo esc_html($check['label']); ?></td><td><span class="edis-badge" data-state="<?php echo esc_attr(strtoupper($check['state'])); ?>"><?php echo esc_html(strtoupper($check['state'])); ?></span></td><td><?php echo esc_html((string)$check['detail']); ?></td></tr><?php endforeach; ?></tbody></table></div>
